# Binary Search Tree Implementation

Here's a comprehensive implementation of a Binary Search Tree with all essential operations:

```python
class TreeNode:
    """Represents a single node in the BST"""
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None


class BinarySearchTree:
    """Binary Search Tree implementation with common operations"""

    def __init__(self):
        self.root = None

    # ==================== INSERT ====================
    def insert(self, value):
        """Insert a value into the BST"""
        if self.root is None:
            self.root = TreeNode(value)
        else:
            self._insert_recursive(self.root, value)

    def _insert_recursive(self, node, value):
        """Helper function to recursively insert a value"""
        if value < node.value:
            if node.left is None:
                node.left = TreeNode(value)
            else:
                self._insert_recursive(node.left, value)
        elif value > node.value:
            if node.right is None:
                node.right = TreeNode(value)
            else:
                self._insert_recursive(node.right, value)
        # If value == node.value, we skip (no duplicates)

    # ==================== SEARCH ====================
    def search(self, value):
        """Search for a value in the BST"""
        return self._search_recursive(self.root, value)

    def _search_recursive(self, node, value):
        """Helper function to recursively search for a value"""
        if node is None:
            return False

        if value == node.value:
            return True
        elif value < node.value:
            return self._search_recursive(node.left, value)
        else:
            return self._search_recursive(node.right, value)

    # ==================== DELETE ====================
    def delete(self, value):
        """Delete a value from the BST"""
        self.root = self._delete_recursive(self.root, value)

    def _delete_recursive(self, node, value):
        """Helper function to recursively delete a value"""
        if node is None:
            return None

        if value < node.value:
            node.left = self._delete_recursive(node.left, value)
        elif value > node.value:
            node.right = self._delete_recursive(node.right, value)
        else:
            # Node with only one child or no child
            if node.left is None:
                return node.right
            elif node.right is None:
                return node.left

            # Node with two children: get the inorder successor
            # (smallest value in the right subtree)
            min_larger_node = self._find_min(node.right)
            node.value = min_larger_node.value
            node.right = self._delete_recursive(node.right, min_larger_node.value)

        return node

    def _find_min(self, node):
        """Find the node with minimum value"""
        current = node
        while current.left is not None:
            current = current.left
        return current

    def _find_max(self, node):
        """Find the node with maximum value"""
        current = node
        while current.right is not None:
            current = current.right
        return current

    # ==================== TRAVERSALS ====================
    def inorder_traversal(self):
        """In-order traversal (Left, Root, Right) - returns sorted list"""
        result = []
        self._inorder_recursive(self.root, result)
        return result

    def _inorder_recursive(self, node, result):
        if node is not None:
            self._inorder_recursive(node.left, result)
            result.append(node.value)
            self._inorder_recursive(node.right, result)

    def preorder_traversal(self):
        """Pre-order traversal (Root, Left, Right)"""
        result = []
        self._preorder_recursive(self.root, result)
        return result

    def _preorder_recursive(self, node, result):
        if node is not None:
            result.append(node.value)
            self._preorder_recursive(node.left, result)
            self._preorder_recursive(node.right, result)

    def postorder_traversal(self):
        """Post-order traversal (Left, Right, Root)"""
        result = []
        self._postorder_recursive(self.root, result)
        return result

    def _postorder_recursive(self, node, result):
        if node is not None:
            self._postorder_recursive(node.left, result)
            self._postorder_recursive(node.right, result)
            result.append(node.value)

    def level_order_traversal(self):
        """Level-order traversal (BFS)"""
        if self.root is None:
            return []

        result = []
        queue = [self.root]

        while queue:
            node = queue.pop(0)
            result.append(node.value)

            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)

        return result

    # ==================== UTILITY METHODS ====================
    def height(self):
        """Get the height of the tree"""
        return self._height_recursive(self.root)

    def _height_recursive(self, node):
        if node is None:
            return -1
        return 1 + max(self._height_recursive(node.left),
                       self._height_recursive(node.right))

    def is_balanced(self):
        """Check if the tree is balanced"""
        def check_balance(node):
            if node is None:
                return True, -1

            left_balanced, left_height = check_balance(node.left)
            if not left_balanced:
                return False, 0

            right_balanced, right_height = check_balance(node.right)
            if not right_balanced:
                return False, 0

            is_balanced = abs(left_height - right_height) <= 1
            height = 1 + max(left_height, right_height)

            return is_balanced, height

        balanced, _ = check_balance(self.root)
        return balanced

    def is_valid_bst(self):
        """Verify if the tree is a valid BST"""
        def validate(node, min_val=None, max_val=None):
            if node is None:
                return True

            if min_val is not None and node.value <= min_val:
                return False
            if max_val is not None and node.value >= max_val:
                return False

            return (validate(node.left, min_val, node.value) and
                    validate(node.right, node.value, max_val))

        return validate(self.root)

    def __str__(self):
        """String representation of the tree"""
        return f"BST(inorder={self.inorder_traversal()})"


# ==================== EXAMPLE USAGE ====================
if __name__ == "__main__":
    bst = BinarySearchTree()

    # Insert values
    values = [50, 30, 70, 20, 40, 60, 80, 10, 25, 65]
    for value in values:
        bst.insert(value)

    print("=== Traversals ===")
    print(f"Inorder:      {bst.inorder_traversal()}")
    print(f"Preorder:     {bst.preorder_traversal()}")
    print(f"Postorder:    {bst.postorder_traversal()}")
    print(f"Level-order:  {bst.level_order_traversal()}")

    print("\n=== Search Operations ===")
    print(f"Search 25: {bst.search(25)}")
    print(f"Search 100: {bst.search(100)}")

    print("\n=== Tree Properties ===")
    print(f"Height: {bst.height()}")
    print(f"Is Balanced: {bst.is_balanced()}")
    print(f"Is Valid BST: {bst.is_valid_bst()}")

    print("\n=== Deletion ===")
    print(f"Before deletion: {bst.inorder_traversal()}")
    bst.delete(20)  # Node with two children
    print(f"After deleting 20: {bst.inorder_traversal()}")
    bst.delete(30)  # Node with two children
    print(f"After deleting 30: {bst.inorder_traversal()}")
    bst.delete(50)  # Root node
    print(f"After deleting 50: {bst.inorder_traversal()}")
```

## Output Example:
```
=== Traversals ===
Inorder:      [10, 20, 25, 30, 40, 50, 60, 65, 70, 80]
Preorder:     [50, 30, 20, 10, 25, 40, 70, 60, 65, 80]
