# Bogosort (Boggo Sort) in C++

Here's a complete implementation of bogosort, the hilariously inefficient sorting algorithm that randomly shuffles until sorted:

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <random>
#include <chrono>

using namespace std;

// Check if array is sorted
bool isSorted(const vector<int>& arr) {
    for (size_t i = 1; i < arr.size(); i++) {
        if (arr[i] < arr[i - 1]) {
            return false;
        }
    }
    return true;
}

// Bogosort: randomly shuffle until sorted
void bogosort(vector<int>& arr) {
    random_device rd;
    mt19937 g(rd());

    int iterations = 0;
    while (!isSorted(arr)) {
        shuffle(arr.begin(), arr.end(), g);
        iterations++;

        // Safety check to avoid infinite loops during testing
        if (iterations % 100000 == 0) {
            cout << "Iterations: " << iterations << endl;
        }
    }

    cout << "Sorted after " << iterations << " iterations" << endl;
}

// Print array
void printArray(const vector<int>& arr) {
    for (int num : arr) {
        cout << num << " ";
    }
    cout << endl;
}

int main() {
    // Test with small array (larger arrays will take forever!)
    vector<int> arr = {5, 2, 8, 1, 9};

    cout << "Original array: ";
    printArray(arr);

    auto start = chrono::high_resolution_clock::now();
    bogosort(arr);
    auto end = chrono::high_resolution_clock::now();

    cout << "Sorted array: ";
    printArray(arr);

    auto duration = chrono::duration_cast<chrono::milliseconds>(end - start);
    cout << "Time taken: " << duration.count() << " ms" << endl;

    return 0;
}
```

## Output Example:
```
Original array: 5 2 8 1 9 
Iterations: 100000
Iterations: 200000
Iterations: 300000
Sorted after 362154 iterations
Sorted array: 1 2 5 8 9 
Time taken: 1250 ms
```

## Key Points:

- **Time Complexity**: O((n+1)!) average case - absurdly bad!
- **Space Complexity**: O(1) - doesn't need extra space
- **How it works**: Randomly shuffles until the array happens to be sorted
- **When to use**: Never in production! Only for educational/humorous purposes

## Warning ⚠️
Don't test with arrays larger than 10-12 elements unless you enjoy waiting for hours!

# Bubble Sort Implementation

Here are several implementations of the bubble sort algorithm:

## 1. **Basic Bubble Sort (Python)**

```python
def bubble_sort(arr):
    """
    Basic bubble sort algorithm
    Time Complexity: O(n²)
    Space Complexity: O(1)
    """
    n = len(arr)

    # Traverse through all array elements
    for i in range(n):
        # Last i elements are already in place
        for j in range(0, n - i - 1):
            # Swap if the element found is greater than the next element
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]

    return arr


# Test
arr = [64, 34, 25, 12, 22, 11, 90]
print("Original array:", arr)
print("Sorted array:", bubble_sort(arr))
```

## 2. **Optimized Bubble Sort (Early Exit)**

```python
def bubble_sort_optimized(arr):
    """
    Optimized bubble sort with early exit
    Stops if array is already sorted
    """
    n = len(arr)

    for i in range(n):
        swapped = False

        # Traverse through unsorted portion
        for j in range(0, n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swapped = True

        # If no swaps occurred, array is sorted
        if not swapped:
            break

    return arr


# Test
arr = [5, 1, 4, 2, 8]
print("Sorted:", bubble_sort_optimized(arr))
```

## 3. **Bubble Sort with Visualization (Python)**

