## 5. Load and Initialize Model

```java
import org.tensorflow.lite.Interpreter;
import java.io.FileInputStream;
import java.nio.channels.FileChannel;
import java.nio.MappedByteBuffer;

public class MLModelHelper {
    private Interpreter tflite;
    private MappedByteBuffer tfliteModel;

    // Constructor
    public MLModelHelper(Context context) {
        try {
            tfliteModel = loadModelFile(context);
            tflite = new Interpreter(tfliteModel);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    // Load model from assets
    private MappedByteBuffer loadModelFile(Context context) throws Exception {
        AssetFileDescriptor fileDescriptor = 
            context.getAssets().openFd("model.tflite");
        FileInputStream inputStream = 
            new FileInputStream(fileDescriptor.getFileDescriptor());
        FileChannel fileChannel = inputStream.getChannel();

        long startOffset = fileDescriptor.getStartOffset();
        long declaredLength = fileDescriptor.getDeclaredLength();

        return fileChannel.map(
            FileChannel.MapMode.READ_ONLY, 
            startOffset, 
            declaredLength
        );
    }

    // Close resources
    public void close() {
        if (tflite != null) {
            tflite.close();
        }
    }
}
```

**Kotlin Version:**
```kotlin
import org.tensorflow.lite.Interpreter
import android.content.Context
import android.content.res.AssetFileDescriptor
import java.io.FileInputStream
import java.nio.MappedByteBuffer
import java.nio.channels.FileChannel

class MLModelHelper(context: Context) {
    private var tflite: Interpreter? = null

    init {
        try {
            val model = loadModelFile(context)
            tflite = Interpreter(model)
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

    private fun loadModelFile(context: Context): MappedByteBuffer {
        val fileDescriptor: AssetFileDescriptor = 
            context.assets.openFd("model.tflite")
        val inputStream = 
            FileInputStream(fileDescriptor.fileDescriptor)
        val fileChannel = inputStream.channel

        val startOffset = fileDescriptor.startOffset
        val declaredLength = fileDescriptor.declaredLength

        return fileChannel.map(
            FileChannel.MapMode.READ_ONLY,
            startOffset,
            declaredLength
        )
    }

    fun close() {
        tflite?.close()
    }
}
```

## 6. Prepare Input Data

```kotlin
// Image Classification Example
class ImageProcessor {
    companion object {
        const val INPUT_SIZE = 224
        const val PIXEL_NORMALIZATION = 255f
    }

    fun preprocessImage(bitmap: Bitmap): ByteBuffer {
        val resizedBitmap = Bitmap.createScaledBitmap(
            bitmap, 
            INPUT_SIZE, 
            INPUT_SIZE, 
            true
        )

        return convertBitmapToByteBuffer(resizedBitmap)
    }

    private fun convertBitmapToByteBuffer(bitmap: Bitmap): ByteBuffer {
        val byteBuffer = ByteBuffer.allocateDirect(
            4 * INPUT_SIZE * INPUT_SIZE * 3
        )
        byteBuffer.order(ByteOrder.nativeOrder())

        val intValues = IntArray(INPUT_SIZE * INPUT_SIZE)
        bitmap.getPixels(
            intValues, 0, INPUT_SIZE, 
            0, 0, INPUT_SIZE, INPUT_SIZE
        )

        var pixel = 0
        for (i in intValues.indices) {
            val value = intValues[i]
            byteBuffer.putFloat(((value shr 16) and 0xFF) / PIXEL_NORMALIZATION)
            byteBuffer.putFloat(((value shr 8) and 0xFF) / PIXEL_NORMALIZATION)
            byteBuffer.putFloat((value and 0xFF) / PIXEL_NORMALIZATION)
        }

        return byteBuffer
    }
}
```

## 7. Run Inference

```kotlin
class InferenceEngine(context: Context) {
    private val modelHelper = MLModelHelper(context)
    private val imageProcessor = ImageProcessor()

    fun classifyImage(bitmap: Bitmap): Pair<String, Float> {
        // Preprocess image
        val inputBuffer = imageProcessor.preprocessImage(bitmap)

        // Prepare output buffer
        val outputArray = Array(1) { FloatArray(1000) } // 1000 classes

        // Run inference
        modelHelper.tflite?.run(inputBuffer, outputArray)

        // Process results
        val results = outputArray[0]
        val maxIndex = results.indices.maxByOrNull { results[it] } ?: 0
        val confidence = results[maxIndex]

        return Pair("Class $maxIndex", confidence)
    }

    fun cleanup() {
        modelHelper.close()
    }
}
```

## 8. Integrate with UI

```kotlin
class MainActivity : AppCompatActivity() {
    private lateinit var inferenceEngine: InferenceEngine
    private lateinit var imageView: ImageView
    private lateinit var resultText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        imageView = findViewById(R.id.imageView)
        resultText = findViewById(R.id.resultText)

        // Initialize inference engine
        inferenceEngine = InferenceEngine(this)

        // Set up image selection
        findViewById<Button>(R.id.selectImageBtn).setOnClickListener {
            selectImage()
        }
    }

    private fun selectImage() {
        val intent = Intent(Intent.ACTION_PICK, MediaStore.Images.Media.EXTERNAL_CONTENT_URI)
        startActivityForResult(intent, REQUEST_CODE_SELECT_IMAGE)
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)

        if (requestCode == REQUEST_CODE_SELECT_IMAGE && resultCode == RESULT_OK) {
            val uri = data?.data
            val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)

            imageView.setImageBitmap(bitmap)

            // Run inference on background thread
            Thread {
                val (label, confidence) = inferenceEngine.classifyImage(bitmap)
                runOnUiThread {
                    resultText.text = "$label (Confidence: ${confidence * 100}%)"
                }
            }.start()
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        inferenceEngine.cleanup()
    }

    companion object {
        const val REQUEST_CODE_SELECT_IMAGE = 100
    }
}
```

