## JavaScript Functionality

```javascript
// SMOOTH SCROLLING
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function (e) {
        e.preventDefault();
        const target = document.querySelector(this.getAttribute('href'));
        if (target) {
            target.scrollIntoView({ behavior: 'smooth' });
        }
    });
});

// DONATION BUTTON HANDLING
document.querySelectorAll('.donation-btn').forEach(btn => {
    btn.addEventListener('click', function() {
        const amount = this.querySelector('.amount').textContent;
        if (amount !== 'Custom') {
            alert(`Redirecting to payment for ${amount}`);
            // In production: window.location.href = paymentGateway;
        } else {
            const customAmount = prompt('Enter donation amount:');
            if (customAmount) {
                alert(`Redirecting to payment for $${customAmount}`);
            }
        }
    });
});

// CONTACT FORM HANDLING
const contactForm = document.querySelector('.contact-form');
if (contactForm) {
    contactForm.addEventListener('submit', function(e) {
        e.preventDefault();
        alert('Thank you for your message! We will get back to you soon.');
        this.reset();
    });
}

// CTA BUTTON HANDLING
document.querySelectorAll('.cta-button').forEach(btn => {
    btn.addEventListener('click', function() {
        const donateSection = document.getElementById('donate');
        if (donateSection) {
            donateSection.scrollIntoView({ behavior: 'smooth' });
        }
    });
});

// NAVBAR HIGHLIGHT ON SCROLL
window.addEventListener('scroll', () => {
    const sections = document.querySelectorAll('section');
    const navLinks = document.querySelectorAll('.nav-menu a');

    let current = '';
    sections.forEach(section => {
        const sectionTop = section.offsetTop;
        if (scrollY >= sectionTop - 200) {
            current = section.getAttribute('id');
        }
    });

    navLinks.forEach(link => {
        link.classList.remove('active');
        if (link.getAttribute('href').slice(1) === current) {
            link.classList.add('active');
        }
    });
});

// ANIMATION ON SCROLL
const observerOptions = {
    threshold: 0.1,
    rootMargin: '0px 0px -100px 0px'
};

const observer = new IntersectionObserver(function(entries) {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.style.opacity = '1';
            entry.target.style.transform = 'translateY(0)';
        }
    });
}, observerOptions);

document.querySelectorAll('.program-card, .stat-card, .testimonial-card').forEach(el => {
    el.style.opacity = '0';
    el.style.transform = 'translateY(20px)';
    el.style.transition = 'all 0.6s ease';
    observer.observe(el);
});
